class Solution:
    def longestMonotonicSubarray(self, nums):
        n = len(nums)
        best = 1
        for i in range(n):
            j = i
            while j + 1 < n and nums[j + 1] > nums[j]:
                j += 1
            best = max(best, j - i + 1)
            j = i
            while j + 1 < n and nums[j + 1] < nums[j]:
                j += 1
            best = max(best, j - i + 1)
        return best

