class Solution:
    def longestMonotonicSubarray(self, nums):
        best = inc = dec = 1
        for i in range(1, len(nums)):
            if nums[i] > nums[i - 1]:
                inc += 1
            else:
                inc = 1
            if nums[i] < nums[i - 1]:
                dec += 1
            else:
                dec = 1
            best = max(best, inc, dec)
        return best

